381	    cfg_rt! {
382	        cfg_unstable_metrics! {
383	            #[inline(always)]
384	            fn inc_budget_forced_yield_count() {
385	                let _ = context::with_current(|handle| {
386	                    handle.scheduler_metrics().inc_budget_forced_yield_count();
387	                });
388	            }
389	        }
